import React, { useState } from 'react'
import { Link, useNavigate } from 'react-router-dom'
import { ToastContainer } from 'react-toastify';
import { handleError, handleSuccess } from '../utils';

function Signup() {

    const [signupInfo, setSignupInfo] = useState({
        name: '',
        email: '',
        password: ''
    })

    const navigate = useNavigate();
    const handleChange = (e) => {
        const { name, value } = e.target;
        console.log(name, value);
        const copySignupInfo = { ...signupInfo };
        copySignupInfo[name] = value;
        setSignupInfo(copySignupInfo);
    }

    const handleSignup = async (e) => {
        e.preventDefault();
        const { name, email, password } = signupInfo;
        if (!name || !email || !password) {
            return handleError('name, email and password are required')
        }
        try {
            const url = `http://localhost:5001/auth/Signup`;
            const response = await fetch(url, {
                method: "POST",
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify(signupInfo)
            });
            const result = await response.json();
            const { success, message, error } = result;
            if (success) {
                handleSuccess(message);
                setTimeout(() => {
                    navigate('/login')
                }, 1000)
            } else if (error) {
                const details = error?.details[0].message;
                handleError(details);
            } else if (!success) {
                handleError(message);
            }
            console.log(result);
        } catch (err) {
            handleError(err);
        }
    }
    return (
        <div className="flex h-screen">
          {/* Left image section */}
          <div className="w-1/2 bg-cover bg-center" style={{ backgroundImage: `url('https://via.placeholder.com/800')` }}>
            {/* Replace with your image URL */}
          </div>

          {/* Right form section */}
          <div className="w-1/2 flex items-center justify-center">
            <div className="w-2/3">
              <h2 className="text-3xl font-bold mb-4">Create Account</h2>
              <p className="text-sm text-gray-600 mb-6">Please enter personal information to continue</p>

              <form>
                <div className="flex gap-4 mb-4">
                  <input
                    type="text"
                    placeholder="First name"
                    className="border border-gray-300 p-2 rounded w-1/2"
                  />
                  <input
                    type="text"
                    placeholder="Last name"
                    className="border border-gray-300 p-2 rounded w-1/2"
                  />
                </div>

                <div className="mb-4">
                  <input
                    type="email"
                    placeholder="Email Address"
                    className="border border-gray-300 p-2 rounded w-full"
                  />
                </div>

                <div className="mb-4">
                  <input
                    type="password"
                    placeholder="Password"
                    className="border border-gray-300 p-2 rounded w-full"
                  />
                </div>

                <div className="mb-4 flex items-center">
                  <input type="checkbox" id="terms" className="mr-2" />
                  <label htmlFor="terms" className="text-sm">
                    Agree to terms and conditions
                  </label>
                </div>

                <button
                  type="submit"
                  className="bg-pink-500 text-white py-2 px-4 rounded w-full hover:bg-pink-600"
                >
                  Create Account
                </button>
              </form>

              <p className="text-sm text-gray-600 mt-4">
                Already have an account? <a href="/login" className="text-pink-500">Login</a>
              </p>
            </div>
          </div>
        </div>
      );
    };

    export default Signup;
